//! # tau-bowl-decode-parity — the SAFETY harness for the live τ-bowl gate.
//!
//! Greedy-decodes a short fixed prompt over the REAL knot TWICE:
//!   1. `TAU_BOWL_DEQUANT_ENABLED` **unset** (baseline — today's exact path),
//!   2. `TAU_BOWL_DEQUANT_ENABLED=1` (gate wired in at the lm_head seam),
//! and ASSERTS the produced token id sequences are **byte-identical** (zero
//! argmax flips). If they differ, that is a FAIL — the tool exits non-zero and
//! the flag must stay off.
//!
//! With the flag ON it also reports the MEASURED gate admit-rate and the
//! certified resident-bit reduction at the real per-step decision margins
//! (`γ = top1 − top2` of the true logits, `‖h‖₂` folded in). Because the gate is
//! observe-only (it never mutates the served logits), token identity is
//! guaranteed by construction — this harness is the empirical proof of that
//! invariant on the real model, plus the honest bit-saving number.
//!
//! Usage:
//!   tau-bowl-decode-parity [--knot PATH] [--prompt id,id,...] [--steps N]
//!                          [--bits B] [--lattice e8|cubic] [--max-rows N]

use distributed_inference::loader::KnotWeights;
use distributed_inference::model::NativeLlamaPipeline;

fn argmax(logits: &[f32]) -> u32 {
    let mut best = 0u32;
    let mut best_val = f32::NEG_INFINITY;
    for (i, &v) in logits.iter().enumerate() {
        if v > best_val {
            best_val = v;
            best = i as u32;
        }
    }
    best
}

/// Per-step gate footprint: (cs_admit_frac, cs_certified_bits/wt, cs_saved_frac,
/// exact_gate_admit_frac, baseline_bits, coarse_bits).
type GateFoot = (f64, f64, f64, f64, f64, f64);

/// Greedy-decode `steps` new tokens from `prompt`, returning the full token id
/// trace and, when `collect_gate`, the per-step gate footprint.
///
/// When `drive_by_substituted` is set, the NEXT token fed back is taken from the
/// gate report's **substituted argmax** (admitted lm_head rows recomputed at the
/// coarse code, missed rows full-precision) instead of the true argmax. This is
/// the genuine no-flip test: if the gate were unsound the substituted token would
/// diverge from the baseline trace and propagate. It also records, per step,
/// whether the substituted argmax equalled the true argmax (`flips`).
fn decode(
    pipeline: &mut NativeLlamaPipeline,
    prompt: &[u32],
    steps: usize,
    collect_gate: bool,
    drive_by_substituted: bool,
) -> (Vec<u32>, Vec<GateFoot>, usize, usize) {
    let mut pos = 0usize;
    let mut produced: Vec<u32> = Vec::new();
    let mut gate: Vec<GateFoot> = Vec::new();
    let mut steps_checked = 0usize; // steps where substitution was computed
    let mut flips = 0usize; // steps where substituted argmax != true argmax

    let mut cur = prompt.to_vec();
    let mut fed = 0usize;
    let total = prompt.len() + steps;
    let mut next_feed_idx = 0usize;
    while fed < total {
        let token = if next_feed_idx < cur.len() {
            cur[next_feed_idx]
        } else {
            break;
        };
        pipeline
            .forward_one(token as usize, pos, false)
            .unwrap_or_else(|e| panic!("forward_one(token={token}, pos={pos}): {e}"));
        if next_feed_idx + 1 >= prompt.len() {
            let true_next = argmax(pipeline.get_logits());
            let report = pipeline.tau_bowl_last_report();
            // The token we COMMIT to (and feed back). Default = true argmax.
            // When driving by substitution, commit the substituted argmax so a
            // real flip would change the trace and cascade.
            let mut next = true_next;
            if let Some(r) = report {
                if collect_gate {
                    let exact_frac = if r.rows > 0 {
                        r.exact_gate_admitted as f64 / r.rows as f64
                    } else {
                        0.0
                    };
                    gate.push((
                        r.admit_frac(),
                        r.certified_bits_per_weight(),
                        r.saved_fraction(),
                        exact_frac,
                        r.baseline_bits,
                        r.coarse_bits,
                    ));
                }
                if r.substitution_checked {
                    steps_checked += 1;
                    if r.substituted_argmax != r.true_argmax {
                        flips += 1;
                    }
                    if drive_by_substituted {
                        next = r.substituted_argmax;
                    }
                }
            }
            produced.push(next);
            if produced.len() >= steps {
                break;
            }
            cur.push(next);
        }
        next_feed_idx += 1;
        fed += 1;
        pos += 1;
    }
    (produced, gate, steps_checked, flips)
}

fn main() {
    let argv: Vec<String> = std::env::args().collect();
    let mut knot = format!(
        "{}/.flux-embed/qwen2.5-0.5b.knot",
        std::env::var("HOME").unwrap_or_default()
    );
    // A short, deterministic real-token prompt (qwen2.5 BPE ids). These are
    // arbitrary valid ids; the harness only needs a non-degenerate context.
    let mut prompt: Vec<u32> = vec![785, 3974, 11, 35681, 11045, 374];
    let mut steps = 12usize;
    let mut bits = 5u32;
    let mut lattice = "e8".to_string();
    let mut max_rows: Option<usize> = None;

    let mut i = 1;
    while i < argv.len() {
        match argv[i].as_str() {
            "--knot" => {
                i += 1;
                knot = argv[i].clone();
            }
            "--prompt" => {
                i += 1;
                prompt = argv[i]
                    .split(',')
                    .filter_map(|s| s.trim().parse::<u32>().ok())
                    .collect();
            }
            "--steps" => {
                i += 1;
                steps = argv[i].parse().unwrap_or(12);
            }
            "--bits" => {
                i += 1;
                bits = argv[i].parse().unwrap_or(5);
            }
            "--lattice" => {
                i += 1;
                lattice = argv[i].clone();
            }
            "--max-rows" => {
                i += 1;
                max_rows = argv[i].parse().ok();
            }
            "-h" | "--help" => {
                eprintln!("usage: tau-bowl-decode-parity [--knot P] [--prompt id,..] [--steps N] [--bits B] [--lattice e8|cubic] [--max-rows N]");
                std::process::exit(0);
            }
            other => {
                eprintln!("unknown arg: {other}");
                std::process::exit(2);
            }
        }
        i += 1;
    }

    // Gate config for the ON run.
    std::env::set_var("TAU_BOWL_DEQUANT_BITS", bits.to_string());
    std::env::set_var("TAU_BOWL_DEQUANT_LATTICE", &lattice);
    if let Some(m) = max_rows {
        std::env::set_var("TAU_BOWL_DEQUANT_MAX_ROWS", m.to_string());
    }
    let full_vocab = max_rows.is_none();

    eprintln!("[tau-bowl-parity] loading knot: {knot}");
    let load = |path: &str| -> NativeLlamaPipeline {
        let kw = KnotWeights::load(path).unwrap_or_else(|e| {
            eprintln!("FATAL: knot load failed: {e:?}");
            std::process::exit(2);
        });
        NativeLlamaPipeline::from_knot(kw, false, 0.8)
    };

    eprintln!(
        "[tau-bowl-parity] prompt={:?} steps={steps} bits={bits} lattice={lattice}",
        prompt
    );

    // ── Run A: baseline (flag OFF) ── today's exact served path; OFF is a strict
    // no-op (the module is never entered).
    std::env::remove_var("TAU_BOWL_DEQUANT_ENABLED");
    std::env::remove_var("TAU_BOWL_DEQUANT_SUBSTITUTE");
    std::env::remove_var("TAU_BOWL_DEQUANT_EXACT");
    let mut pa = load(&knot);
    assert!(
        !distributed_inference::tau_bowl_dequant::enabled(),
        "flag must be OFF for the baseline run"
    );
    let (toks_off, _, _, _) = decode(&mut pa, &prompt, steps, false, false);
    drop(pa);
    eprintln!("[tau-bowl-parity] OFF tokens: {:?}", toks_off);

    // ── Run B: gate ON + SUBSTITUTE ON ── recompute admitted lm_head rows at the
    // coarse code and DRIVE decode by the substituted argmax, so any real flip
    // would diverge the trace and cascade. Served logits are still untouched.
    std::env::set_var("TAU_BOWL_DEQUANT_ENABLED", "1");
    std::env::set_var("TAU_BOWL_DEQUANT_SUBSTITUTE", "1");
    // Drive the actual swap by the EXACT (sound) gate so the no-flip test is
    // NON-VACUOUS — it really substitutes the ~half of rows the exact gate admits
    // and checks the token still doesn't move. The conservative C–S gate admits
    // ~nothing on this knot (would make the test vacuous).
    std::env::set_var("TAU_BOWL_DEQUANT_EXACT", "1");
    let mut pb = load(&knot);
    assert!(
        distributed_inference::tau_bowl_dequant::enabled(),
        "flag must be ON for the gated run"
    );
    assert!(
        distributed_inference::tau_bowl_dequant::substitute_enabled(),
        "substitute sub-flag must be ON for the gated run"
    );
    let (toks_on, gate, steps_checked, flips) =
        decode(&mut pb, &prompt, steps, true, true);
    drop(pb);
    eprintln!("[tau-bowl-parity] ON  tokens: {:?}", toks_on);

    // ── The safety assertion ──
    let identical = toks_off == toks_on;

    // Aggregate the measured gate footprint over the ON run.
    let n = gate.len().max(1);
    let mean_admit = gate.iter().map(|g| g.0).sum::<f64>() / n as f64;
    let mean_cert_bits = gate.iter().map(|g| g.1).sum::<f64>() / n as f64;
    let mean_saved = gate.iter().map(|g| g.2).sum::<f64>() / n as f64;
    let mean_exact = gate.iter().map(|g| g.3).sum::<f64>() / n as f64;

    println!("\n[tau-bowl-decode-parity] — live forward-path gate, real knot");
    println!("  knot               = {knot}");
    println!("  prompt             = {prompt:?}");
    println!("  steps              = {steps}");
    println!("  coarse code        = {lattice}-{bits}b");
    println!(
        "  row coverage       = {}",
        if full_vocab {
            "FULL vocab (every lm_head row gated+substituted)".to_string()
        } else {
            format!("CAPPED at {} rows (subset — see caveat)", max_rows.unwrap())
        }
    );
    println!("  OFF token sequence = {toks_off:?}");
    println!(
        "  ON  token sequence = {toks_on:?}  (driven by SUBSTITUTED argmax, EXACT gate swap)"
    );
    println!(
        "  TOKEN IDENTITY     = {}",
        if identical {
            "IDENTICAL ✓ (zero argmax flips)"
        } else {
            "DIVERGED ✗ — FAIL"
        }
    );
    println!(
        "  per-step substitution checks = {steps_checked} steps, {flips} argmax flip(s)"
    );
    if !gate.is_empty() {
        println!("  gate steps measured= {}", gate.len());
        println!("  mean admit-rate    = {:.2}%", 100.0 * mean_admit);
        println!(
            "  certified bits/wt  = {:.4}  (mean over steps; lm_head baseline)",
            mean_cert_bits
        );
        println!(
            "  C–S admit-rate     = {:.2}%  (conservative ‖τ‖₂·‖h‖₂ gate — ~0 on this knot)",
            100.0 * mean_admit
        );
        println!(
            "  C–S resident saved = {:.2}%  (what the SHIPPED conservative gate realizes)",
            100.0 * mean_saved
        );
        // The EXACT (sound) gate is what actually DROVE the substitution above.
        // Certified resident bits under it = coarse·exact + baseline·(1−exact).
        let base_b = gate.first().map(|g| g.4).unwrap_or(8.0);
        let coarse_b = gate.first().map(|g| g.5).unwrap_or(bits as f64);
        let exact_saved = if base_b > 0.0 {
            ((base_b - coarse_b) / base_b) * mean_exact
        } else {
            0.0
        };
        println!(
            "  EXACT admit-rate   = {:.2}%  (sound |⟨h,τ⟩| ≤ γ/2 gate — drove the swap above)",
            100.0 * mean_exact
        );
        println!(
            "  EXACT resident saved = {:.2}%  ({}b coarse over {}b baseline at that admit-rate)",
            100.0 * exact_saved,
            coarse_b as u32,
            base_b as u32
        );
    } else {
        println!("  (no gate reports collected — was the flag honored?)");
    }

    // FAIL conditions: a diverged trace OR any per-step substituted-argmax flip.
    if !identical || flips > 0 {
        eprintln!(
            "\nFAIL: gated substitution flipped a token ({flips} per-step flip(s); sequence identical={identical}). Flag must stay OFF; do NOT loosen the gate."
        );
        std::process::exit(1);
    }

    if full_vocab {
        println!(
            "\n  VERDICT: SHIP-able as a measured no-op — the EXACT (sound) gate substituted the\n  coarse code on ~{:.0}% of FULL-vocab lm_head rows every step and the produced\n  token sequence stayed byte-identical ({steps_checked} steps, 0 flips), for\n  ~{:.1}% certified resident-bit saving on the lm_head. The conservative C–S gate\n  saved {:.1}% (admits ~nothing here — Cauchy–Schwarz is the blocker, not the\n  code). Served logits remain full-precision; keep the default-OFF flag until\n  Taylor opts to flip serving over to the EXACT gate.",
            100.0 * mean_exact,
            100.0 * (gate.iter().map(|g| ((g.4 - g.5) / g.4) * g.3).sum::<f64>()
                / gate.len().max(1) as f64),
            100.0 * mean_saved
        );
    } else {
        println!(
            "\n  VERDICT: HOLD — no flips over the CAPPED {} rows (EXACT gate swapped ~{:.0}% of\n  them), but a capped run only gates a subset of the vocab and can HIDE a flip in\n  an ungated row. Re-run WITHOUT --max-rows for a full-vocab SHIP verdict.",
            max_rows.unwrap(),
            100.0 * mean_exact
        );
    }
}
